INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027c40e3c98b0941765a2a', '服务很周到，门童会主动打招呼并帮忙拿行李，去客房电梯口也有工作人员指引，checkin柜台小姐姐Viria很热情且耐心。酒店环境不错，后面有个小花园，唯一欠缺是房间设施有些旧了，卫生间通风换气不佳。', '["https://dimg04.c-ctrip.com/images/0232z12000d9gf3sb94C5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230e12000d9gej8762E0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231a12000d9gebu48428_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-02-21', '红棉大床套房', '套房', '家庭亲子', 99, 0, 5, 8, '["前台服务","房间设施","整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度'),
('68027c40e3c98b0941765a2b', '有史以来入住等待时间最久的一家酒店，大堂人员嘈杂，乱哄哄的，体验极差，前台服务人员一点不急，在那里慢吞吞的。客房装修老旧，堪比快捷酒店。水龙头设计不合理，一打开水溅的台面上一塌糊涂。淋浴和马桶共用一扇门，关上淋浴，用马桶的就没有门了，敞开着上厕所。奇葩省钱装修。淋浴间瓷砖破损，茶几磨损严重，还在坚持给客人使用。完全与五星不搭。这个酒店真是金玉其外……。', '["https://dimg04.c-ctrip.com/images/0230s12000d6pfgw9F0B8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232g12000d6pgw4fD345_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.5, 2, '2024-02-12', '花园双床房', '双床房', '其他', 177, 2, 7, 9, '["前台服务","房间设施","整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度'),
('68027c40e3c98b0941765a2c', '环境不错 行李生服务特别好  客房大姐也很热情', '["https://dimg04.c-ctrip.com/images/0232s12000ehpvuldD3D4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000ehpyrl92A6E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230g12000ehpxi63DDC0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-16', '花园大床房', '大床房', '朋友出游', 23, 0, 4, 5, '["前台服务","客房服务"]'::jsonb, '前台服务', '客房服务', NULL),
('68027c40e3c98b0941765a2d', '花园酒店除了地理位置优越，服务几十年来没有任何降低，酒店的房间干净大气，充分体现国际酒店的水平。酒店的各类服务人员，态度和素质非常高，超越很多新的酒店。广州酒店，首选花园酒店是绝对不会错的', '["https://dimg04.c-ctrip.com/images/0232a12000d8adntt392A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-17', '城央绿意大床房', '大床房', '家庭亲子', 94, 0, 28, 8, '["整体满意度","前台服务","卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况'),
('68027c40e3c98b0941765a2e', '入住环境真的是很好，酒店自带一个那么大花园很惊叹了。而且春节期间，过年气氛搞得特别浓，特别喜庆热闹，感觉随时有节目随时有惊喜，孩子遇到好几次财神高兴的不得了，几块金币巧克力带来的欢乐??愉快了整个旅程。服务也很好，热情又主动，前台接待、大堂经理、餐厅工作人员都很积极。整体入住体验很满意。', '["https://dimg04.c-ctrip.com/images/0235w12000d98wbus72E3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234d12000d98w5ozAA02_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231112000d98vz9m4163_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232d12000d98wbv0E917_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-20', '红棉大床套房', '套房', '家庭亲子', 144, 0, 9, 9, '["整体满意度","前台服务","公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施'),
('68027c40e3c98b0941765a2f', '第2次入住花园，地理位置好，离北京路很近，办理入住可以再便捷快一点，房间干净，床垫偏软，早餐在一楼，地方不大，有安排座位，餐品一般，种类不多，参观了花园博物馆，里面陈列的是以花园酒店为主的广州酒店发展史。总体感觉一般。', '["https://dimg04.c-ctrip.com/images/0233012000d7ma3gqA78B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235v12000d7ma54l8432_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-02-15', '花园双床房', '双床房', '朋友出游', 109, 0, 4, 7, '["周边配套","退房/入住效率","卫生状况"]'::jsonb, '周边配套', '退房/入住效率', '卫生状况'),
('68027c4be3c98b0941765a30', '房间总体保养不错，就是淋浴下水有些不畅，可能是时代有些久远。酒店内瀑布花园，顶层 360旋宫餐厅是酒店亮点，住酒店有空值得一去。旋宫可以俯视全城美景，瀑布花园小而精致，很有岭南风味，点赞！', '["https://dimg04.c-ctrip.com/images/0230h12000d7o92ef14C0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235h12000d7o9dyw1A84_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234e12000d7o0qglD729_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236m12000d7nzoe80DD7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-15', '城央绿意双床房', '双床房', '家庭亲子', 94, 0, 4, 8, '["房间设施","公共设施","景观/朝向"]'::jsonb, '房间设施', '公共设施', '景观/朝向'),
('68027c4be3c98b0941765a31', '每次来广州都喜欢住花园酒店，酒店服务始终保持着传统的管家式的贴心，行李房，楼层管理，房间整理，都一如既往地规范有礼，路上员工也会主动跟客人打招呼，而且酒店大堂的布置总是那么富有岭南特色。', '["https://dimg04.c-ctrip.com/images/0232e12000d9bhs19EBCF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232d12000d9bhe0cB10A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-21', '花园大床房', '大床房', '独自旅行', 93, 0, 14, 9, '["前台服务","客房服务","整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度'),
('68027c4be3c98b0941765a32', '酒店环境很好，瀑布餐厅很美，服务很好，办理入住送了鲜花，房间整体不错，有迎宾水果，过生日还送了蛋糕，服务员Amy写的小卡片很贴心，很不错的入住体验，下次来广州还会考虑住花园酒店！', '["https://dimg04.c-ctrip.com/images/0234i12000h4pbgag2A1A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233f12000h4p4yb18FD3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-12-10', '花园双床房', '双床房', '朋友出游', 89, 0, 1, 8, '["整体满意度","前台服务","客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务'),
('68027c4be3c98b0941765a33', '作为老广，花园酒店一直都是属于高档酒店的存在，没想到入住大失所望，房间设施陈旧就不说了，浴室卫生简直以灾难级形容，大理石裂的，洗脸盆和淋浴间的霉菌简直吓人，很难想象跟星级扯上关系', '["https://dimg04.c-ctrip.com/images/0236x224x8u1bbeva867C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230l224x8u1cd07b2F68_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02359224x8u1cdw3j362D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02337224x8u1bnuz2593F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231q224x8u1bbevcE5F0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234d224x8u1b2ynyDBCD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02303224x8u1cd07dB629_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234m224x8u1cfbfgFDDB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236z224x8u1bz417FE33_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.2, 2, '2024-02-15', '红棉大床套房', '套房', '情侣出游', 89, 18, 8, 9, '["房间设施","卫生状况"]'::jsonb, '房间设施', '卫生状况', NULL),
('68027c4be3c98b0941765a34', '选择住花园酒店时还有点纠结，虽然也是五星，但年代久远，硬件设施确实还有改进的空间，但也因为是老牌五星，对于我们这种没体验过的外地游客而言，还是很新奇，瀑布、花园、博物馆这些无论对于大人还是孩子而言，都还是不错的体验。应该说特色突出，值得一试。但是入住和退房都要排队，有点尴尬，携程的铂金会员也要押金，好在办了个岭南酒店金卡，送了小朋友早餐还是不错的，而且瀑布餐厅和楼上的旋转餐厅，孩子都很喜欢，总体来说还是很满意的！对了，在地铁口也非常重要，超级方便！', '["https://dimg04.c-ctrip.com/images/0236x12000dgi8s56305C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230l12000dgi8svqC8C7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232812000dgi8ue63237_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230512000dgi95cfDEF4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-03-20', '花园大床房', '大床房', '家庭亲子', 226, 0, 9, 9, '["整体满意度","交通便利性","退房/入住效率"]'::jsonb, '整体满意度', '交通便利性', '退房/入住效率'),
('68027c4be3c98b0941765a35', '家庭出游定了双床房，整个交通，酒店环境都还不错。但只有三分的原因就是这个洗手间和浴缸（没有淋浴间）是正对房间两个床，也就是家里有异性的话，无可避免的要有几分钟暴露时间，因为你不能在浴缸里穿衣服，而且也没地方放干净的衣服，如果家里有老人，跨进跨出洗澡还非常有难度！这个设计是我不能理解的。就算是好朋友一起出游，我想也不太好意思洗完澡出来就被看光吧？？？
另外，我在六楼，需要补给我去找走廊打扫的小妹，外籍小姑娘说“听不懂”，只能用英语交流，我想说，你在中国的土地上打工，你听不懂？？？这个需要客房部培训一下了。我可以讲英语，但是你不能不会中文哦！', '["https://dimg04.c-ctrip.com/images/0233112000d6d6stbD701_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z12000d6de616286D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231n12000d6d53jg7C8D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3, 3, '2024-02-11', '城央绿意双床房', '双床房', '家庭亲子', 272, 1, 16, 9, '["房间设施","客房服务"]'::jsonb, '房间设施', '客房服务', NULL),
('68027c4be3c98b0941765a36', '孩子们非常喜欢花园酒店，装修精致，服务贴心，后花园景色优美，欣赏瀑布尝心悦目，酒店的文创商品也非常有特色，荔湾亭的食物让人流连忘返，酒店交通便捷，距离地铁站很近，酒店各方面都让人很满意，下次还会入住。', '["https://dimg04.c-ctrip.com/images/0233p12000d8a1ojt7045_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230312000d8a0p6yAF5E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232912000d89um1d1DAF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235912000d89y9n73564_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000d8a2lm9A923_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-17', '花园大床房', '大床房', '家庭亲子', 100, 0, 5, 8, '["整体满意度","周边配套","交通便利性"]'::jsonb, '整体满意度', '周边配套', '交通便利性'),
('68027c4be3c98b0941765a37', '酒店非常气派，大开眼界！ 长辈都夸好。
定的64平的套房，宽敞舒适，客房服务响应及时，行李搬运也到位。
第一天图省事去了荔湾艇吃饭，有点不愉快，性价比不高。
下次还会选择入住花园酒店，吃饭还是去外面吃更好。', '["https://dimg04.c-ctrip.com/images/0230l12000d5gnaw1A048_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234z12000d5gm5e4060E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235412000d5gmove385E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231412000d5gnb1s8B55_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000d5gnb1w1AA9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-07', '红棉双床套房', '套房', '家庭亲子', 103, 0, 17, 7, '["整体满意度","客房服务","性价比"]'::jsonb, '整体满意度', '客房服务', '性价比'),
('68027c4be3c98b0941765a38', '这次旅行挑酒店??最快，选了花园酒店。看评价差评多有点忐忑但是一下车真的很棒，门童主动拿行李??，每个服务人员态度好，办理入住也特别快，房间干净整洁，有咖啡机胶囊咖啡免费，和新加坡????茶。连住三晚每天及时打扫??。酒店的桃园亭吃的早茶，人特别少，味道不错就是贵和白天鹅??差不多优点就是不用排队，就两三桌。酒店门口很近就有点都德，对面的街有好多好吃的嫌北京路远可以去酒店对面溜溜，还有个优点就是离地铁站非常近这个是我选择这个酒店的重要原因！唯一缺点就是不能开窗，身为北方人总觉得有点潮味儿。总之很满意放心入住', '["https://dimg04.c-ctrip.com/images/0231x12000d7sezd24052_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236m12000d7setzhB78E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236p12000d7sf6gj87CC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232t12000d7sezd47D41_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-02-16', '花园大床房', '大床房', '家庭亲子', 256, 1, 6, 9, '["前台服务","交通便利性","卫生状况"]'::jsonb, '前台服务', '交通便利性', '卫生状况'),
('68027c4be3c98b0941765a39', '每家五星级酒店都有自己的风格！广州花园酒店拥有自己的博物馆，自己的花园，自己的米其林餐厅！可以媲美上海的和平饭店??！客房服务真的非常人性化！感觉宾至如归！来广州过年，花园酒店的布景，年味浓郁！感觉特别好！', '["https://dimg04.c-ctrip.com/images/0203j12000d61vpn67489_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0235y12000d61irig6C8E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231h12000d61mn7t5856_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236812000d61v8nh12A6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235z12000d61j3m4223B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234g12000d61ijgx30B6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232m12000d61npig8680_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-09', '花园双床房', '双床房', '家庭亲子', 103, 0, 3, 9, '["整体满意度","客房服务","餐饮设施"]'::jsonb, '整体满意度', '客房服务', '餐饮设施'),
('68027c56e3c98b0941765a3a', '慕名而来，酒店服务各方面还可以。因为我们山西大同也有个花园酒店非常棒的，听说他们都美食就是在这里学习的说以想感受一下，也许不适合我们北方人都口味，感觉还是我们大同美食才是天下第一，欢迎大家来大同感受一下，', '["https://dimg04.c-ctrip.com/images/0205z12000d9r4bl53476_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0231o12000d9qxlwl5B44_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231o12000d9r39oe02C9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234g12000d9qp18dD65F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-22', '花园双床房', '双床房', '家庭亲子', 102, 0, 20, 4, '["餐饮设施","整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL),
('68027c56e3c98b0941765a3b', '酒店正门右边就是地铁5号线淘金站，交通便利，不想坐地铁，服务员会在外面帮你叫出租车，服务非常好！
酒店大堂装潢非常漂亮，接待入住的前台美女服务也特别热情！早餐种类也非常丰富，你可以选择在一楼的瀑布餐厅，也可以选择在30楼旋转餐厅用餐！个人偏向推荐一楼瀑布餐厅，但是要记得早点去，八点半九点时去的话有可能需要排队等位哟！
房间也非常干净，每天都会打扫，如果你在房间开了请勿打扰，服务员也会打电话询问是否打扫房间，什么时间打扫房间合适，所以服务特别贴心！
大年初一那天酒店还请来了专业的舞狮团队来表演，特别哇塞！', '["https://dimg04.c-ctrip.com/images/0206712000d7o39bbA1A6_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0235q12000d7o1r2qAFFB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230y12000d7nsvv6D78C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d12000d7nwbof4153_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-15', '红棉大床套房', '套房', '家庭亲子', 254, 0, 2, 9, '["交通便利性","前台服务","客房服务"]'::jsonb, '交通便利性', '前台服务', '客房服务'),
('68027c56e3c98b0941765a3c', '都很满意，出地库就有漂亮小姐姐帮忙拿行李引路。还有欢迎糖果，和离店小礼物。酒店后花园是隐藏在闹市里的世外桃源，美美的！很出片！下次去还住花园酒店！周边很方便，饭后遛食，一杯小酒惬意的很！', '["https://dimg04.c-ctrip.com/images/0234m12000d7b2ym55209_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236112000d7b2eqh5649_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230b12000d7b2whd5DD9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236312000d7b2xik9C05_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231k12000d7b3b3z80C3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234m12000d7b3mm699AE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231u12000d7b3hs2F3D8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233812000d7b2iiiE39C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-14', '城央绿意双床房', '双床房', '朋友出游', 93, 0, 2, 8, '["整体满意度","前台服务","周边配套"]'::jsonb, '整体满意度', '前台服务', '周边配套'),
('68027c56e3c98b0941765a3d', '花园酒店真的是目前住过最有底蕴的酒店，一进入大厅就能感受到。前台办理入住非常快，虽然排队的人多但是窗口非常多很快就到了。前台Gillian非常专业迅速，得知我们是金卡会员并且过生日迅速安排房型升级超级认真负责，还送了鲜花超好评。行政酒廊待遇也非常全面，包含了早餐，下午茶和晚上的欢乐时光。
早餐种类非常多，在30楼旋转餐厅，每次都会带领我们入座。在我们记错时间错过下午茶时间后，Carrie女士立刻为我们安排第二天补上。即使不在服务时间，另外几位女士也为我们制作了两杯咖啡。二天我们入座后Carrie立刻前来询问我们的需求。
此外，我们住宿的16层电梯口也也服务的女生，我们安排电梯。
花园酒店的服务团队非常非常专业，非常庆幸这次能够选择花园酒店。', '["https://dimg04.c-ctrip.com/images/0232x12000euns61q4F60_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236o12000eunvsyw002A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234212000eunsaaoFADC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233o12000eunr5cgC79B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232g12000eunlun62212_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-21', '花园双床房', '双床房', '家庭亲子', 324, 0, 6, 9, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68027c56e3c98b0941765a3e', '非常巨大的酒店，所以入住要排队很久……大厅很国际化，设施还不错。第一次安排的房间一进门就是浓浓的蒜蓉生蚝味道，虽说闻起来不错，可实在不适合入住吧。之前就听闻早餐是米其林级别的，所以都订购了含早的房型，第一天体验还可以，虽说选择不多，餐厅比较小，有点局促，但餐厅后的瀑布还比较特别。第二天的早餐因为人太多，被忽悠到了旁边的酒吧，进去前一直被告知菜品是一样的，结果酒吧里不仅很冷，还没什么吃的，本来没什么胃口，只想喝完热粥，哪知道连这么卑微的要求都不能满足。敞开的粥锅里只剩一个底儿，还得排队抢，好不容易盛好了粥，还居然是冰粥。酒吧的服务人员一直在保障外国友人，国人在她们眼中，大概就是被施舍的吧，体验非常非常差，这样的品质也好意思说自己米其林？也好意思收200+的价格？现在是2024年了，拜托酒店醒醒吧，不是只有服务好外国友人就可以万事大吉的时候了。很糟糕的体验。再也不会来这样一家徒有虚名的虚伪酒店了。', '["https://dimg04.c-ctrip.com/images/0235812000d914evn8F54_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.5, 2, '2024-02-20', '花园大床房', '大床房', '家庭亲子', 402, 7, 13, 9, '["餐饮设施","整体满意度","性价比"]'::jsonb, '餐饮设施', '整体满意度', '性价比'),
('68027c56e3c98b0941765a3f', '著名的花园酒店，非常喜欢那种文化气息和岁月的底蕴，同时自然也会有设施维护的问题，比如用水时下水管道会发出响声，沙发上会有污渍，但服务也非常周到，除了入住时前台不清楚套餐包含的桃园馆餐次数，说要核实后告知，不过一直没有回音，后来主动问过一次，也没有回话，除此而外，服务特别好，比如无论去餐厅还是乘电梯都有人引导，退房体验特别好特别方便以及人性化。下午茶和欢乐时光体验也很美好。总之，满意，再去广州会再选花园。', '["https://dimg04.c-ctrip.com/images/0235f12000d59v0c7125D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230512000d5aijkzEAF2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231a12000d5aiin2059E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-02-06', '粤韵双床套房', '套房', '家庭亲子', 203, 0, 6, 8, '["整体满意度","房间设施","前台服务"]'::jsonb, '整体满意度', '房间设施', '前台服务'),
('68027c56e3c98b0941765a40', '购买了携程3晚连住花园双床房含早3600套餐，提前一周预约了房间。出发前一天跟客房部打电话确认房型，要求高楼层安静无烟，对方回答会给备注。当天20点到达办理入住，说是帮我帮忙升级了9楼的城央绿意房，上去查看900是位于电梯间后面，浴缸和淋浴同处一处，考虑带孩子使用不便，便座机酒店客房部要求原房型入住。结果被告知已无类似房型。那么问题来了，我之前的全款预约、电话确认是为了什么？！座机沟通后被告知还有一间花园双床房在打扫，但无浴缸。我提出可否参观一下，被拒绝，并且打扫需要1.5小时左右，就是22点半以后！！毫无选择的我只能致电携程客服帮忙解决～就这么等了50分钟酒店和携程都没有任何回复。第三次致电携程后仍没有确切回复，自行前往大堂前台直接理论。诉求和理由同上。在前台交涉了50分钟，最终给了间23楼的红棉大床房加床处理，入住时接近22:30。我们不是无理取闹的人，只是争取合理的权益。好在后续酒店和携程在催促下有积极处理，结果还是满意的。说说酒店本身，地处老城区，餐饮交通真的方便。顶楼旋转餐厅风景好，餐食和服务都不错。所在楼层会有电梯间引导服务员，每次见面问好并确认房间号，挺安全的。图1-3是9楼的城央绿意房，除了浴缸淋浴不合理，其余中规中矩。图4是新装修的红棉房，推荐入住。携程平台还是很注意客户感受的，继续支持！', '["https://dimg04.c-ctrip.com/images/0234x12000d5um70s1B80_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000d5u8fjzE728_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236112000d5ujepx30C1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234c12000d5uchav48C0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-02-08', '花园双床房', '双床房', '家庭亲子', 562, 0, 26, 9, '["前台服务","退房/入住效率","房间设施"]'::jsonb, '前台服务', '退房/入住效率', '房间设施'),
('68027c56e3c98b0941765a41', '房间干净，环境很好', '["https://dimg04.c-ctrip.com/images/0233112000eroqusg1AE9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235c12000erojtjw6044_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233112000eroquky5D33_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-13', '红棉大床套房', '套房', '情侣出游', 9, 0, 12, 4, '["卫生状况","整体满意度"]'::jsonb, '卫生状况', '整体满意度', NULL),
('68027c56e3c98b0941765a42', '不知道为什么会有许多差评，对于一个比较挑剔的住客来讲首先我认为不错的。选了家庭大床房，服务很好，酒店下车时工作人员主动帮忙搬行李，每层都有导引人员，其次房间虽然不是非常大，但是干净温馨而舒适。巴基斯坦的小伙子很热情。作为白金五星酒店四楼的博物馆一定要去看看，那是时代的缩影，还有后花园，繁华喧嚣中的宁静与美好。唯一的遗憾是瀑布餐厅的早餐因为周六客满被换到了旋转餐厅，希望这一项能够改善，至少要保证住店客人用餐。', '["https://dimg04.c-ctrip.com/images/0230u12000d49hbp170F7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000d49tivrDCE2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236g12000d49w5zd725C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-03', '花园大床房', '大床房', '家庭亲子', 205, 0, 1, 9, '["整体满意度","前台服务","卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况'),
('68027c56e3c98b0941765a43', '晚上7点多到的，前台给我们升级了套房，房间大一倍，非常满意。
房间舒适干净，又大，非常满意
酒店就是个花园，瀑布，亭台楼阁，又有深厚的文化底蕴，4楼有个酒店博物馆，好逛，非常满意
工作人员服务态度很好，看到住客主动打招呼，还有不同的活动领了冰箱贴，非常满意！
下次还会再来住！', '["https://dimg04.c-ctrip.com/images/0234i12000d5yk4u61E41_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000d5yjk4wEBB4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p12000d5yk7of383A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-09', '花园双床房', '双床房', '家庭亲子', 138, 0, 13, 8, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('68027c61e3c98b0941765a44', '第一次入住，很成熟高雅的酒店。花园酒店的Rebecca还给升级了房间，必须点个赞！', '["https://dimg04.c-ctrip.com/images/0233112000e3h02acC28E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237112000e3gycdi0688_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231512000e3gzph884F1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-21', '花园大床房', '大床房', '其他', 41, 0, 1, 6, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68027c61e3c98b0941765a45', '满意，舒服！安娜和李文服务热情周到，保洁员对客户提出要求及时记录（服务满意）餐厅早餐美味，旁边有瀑布环境舒适', '["https://dimg04.c-ctrip.com/images/0230l12000jh0mcb0F34C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000jh05eu2E3FD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235312000jgzufl75FF4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-01', '红棉大床套房', '套房', '情侣出游', 54, 0, 3, 7, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68027c61e3c98b0941765a46', '房间的设施有点老旧了，酒店大堂和后花园还可以。这酒店住的老外挺多的，重点来了。因为老外多，我发现大厅餐厅的服务员就比较**，我们去吃早饭的时候遇到同样一起排队的老外就分在能看见瀑布的位置视野开阔，光线明亮，我们一家三口分的位置就是最最角落的不要说看看瀑布了连光线都很暗的，家人们谁懂啊，花600多就是去打卡瀑布的好吗。我看见我们前面的三个老外就坐的位置很好，我当时就emo了，问服务员有没有位置好点的嘛？大厅不是有很多空位置吗？我想坐到那边去，她说啊那是有人坐的，他们都在取餐，一边说的时候一边微笑，我听了就不开心了，吃饭的心情也没有，过一会不知怎么的大概看我不开心就给我们换位置到大厅了，重点来了，我去取咖啡的时候杯子着急拿走服务员就跟我说no finished 谁懂啊，我一中国人在广州玩又没有出国说啥英语啊，真的醉了，咱不是说排斥英语啊，就你环顾四周的时候就发现坐大厅好位置的都是老外，我严重怀疑这酒店服务员是**。最后酒店早餐真的很一般就同是五星级酒店的早餐来比不能说最差的，实在是一般。不建议去吃。', '["https://dimg04.c-ctrip.com/images/0236112000d43ak44002F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231n12000d439zl62586_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235s12000d43arke538E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.2, 3, '2024-02-03', '花园双床房', '双床房', '家庭亲子', 454, 1, 1, 8, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('68027c61e3c98b0941765a47', '超级漂亮的酒店，地理位置非常好，整个酒店进门就是香香的，给我们升级了套房，三大一小住起来很宽敞，很舒服的一次旅行，客房还送了小书包跟水果给宝宝，特别用心呢', '["https://dimg04.c-ctrip.com/images/0232j12000dctkqbr9A37_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231m12000dct83q77958_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d12000dcth2f6EC16_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231612000dctjphy62BD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000dctl6baA3A2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000dct7vjhBFC7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232v12000dctoc29A7E8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-06', '红棉大床套房', '套房', '家庭亲子', 77, 1, 7, 8, '["整体满意度","客房服务","周边配套"]'::jsonb, '整体满意度', '客房服务', '周边配套'),
('68027c61e3c98b0941765a48', '酒店位置很好，环境优美，服务到位，床品舒服，早餐纯西式，周边有广东酒家、点都德早茶非常不错！卫生需要注意，咖啡机和水壶感觉都不太干净！过年气氛很浓，大堂有自己的集市和乐队，热热闹闹，开开心心！', '["https://dimg04.c-ctrip.com/images/0234712000d5rdzk6E556_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000d5remy15829_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235r12000d5rf5k569E9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236p12000d5rfevsB913_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233z12000d5rdddt189B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230g12000d5rf5k995A5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-02-08', '花园大床房', '大床房', '家庭亲子', 96, 0, 18, 8, '["周边配套","整体满意度","卫生状况"]'::jsonb, '周边配套', '整体满意度', '卫生状况'),
('68027c61e3c98b0941765a49', '这是我住过最差的酒店（更别说是五星级酒店了），比招待所都不如，还五星。房间和卫生间冲凉房直通，冲凉换衣服都不方便，而且设施非常残旧，真的是招待所的硬件。
    冲凉房居然就是一个浴缸，排水又慢，冲个凉简直就是水漫金山，水泡到脚腕，无法排水，而且在浴缸跨来跨去影响人身安全，出来就是房间，无任何遮挡，招待所都不是如此吧？岂有此理！！
    卫生间又窄又残旧，进去又不方便，就是个招待所不如的地方。
    房间又小可能 10 平方左右，而且床又残旧，地板更残旧，反正没一样东西是好的。就是乡下的招待所都比花园酒店客房好。反正谁住谁遭殃。看看图片就知道。差评！差评！差评！重要事情说三遍！！', '["https://dimg04.c-ctrip.com/images/0236i12000d3119ic90B7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236s12000d30qrm5AF24_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232l12000d30qebnF6A5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000d316hju06F2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236l12000d30v4171095_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1, 1, '2024-01-30', '花园双床房', '双床房', '家庭亲子', 295, 8, 60, 9, '["房间设施","卫生状况","整体满意度"]'::jsonb, '房间设施', '卫生状况', '整体满意度'),
('68027c61e3c98b0941765a4a', '预订酒店时备注了这次入住是为了过生日如果情况允许希望能安排上好一点的房间。晚上九点到店办入住时迎来了小小客流高峰，需要排队等候。办理入住手续的时候，前台小姐姐Betty 安排了一个超完美的房间，她还特意提醒我房号是精心设置了一个“好意头”的房间，还热情的给我送了几支花花。真的是太有趣了！房间安排了升级，打开房门发现房间有主题精心布置过，还有新鲜的欢迎水果，非常感谢客房姐姐的安排！房间里处处都是细节，房间桌子上摆放着酒店不同餐厅不同特色打卡点的酒店指南，图文并茂有趣又生动。连墙上挂着的装饰画都有印着二维码，好奇地拿手机一扫，显示出来的就是客房里房间装饰上蕴含的各种岭南文化元素。让我异常惊喜的是，短短的文章中透露出不同的岭南特色文化，有种让住客在入住期间都能感受到这个酒店的文化底蕴和用意。唯一一个小小的插曲大概是我们不知道今天酒店会有赠送蛋糕到房间的这个惊喜。所以早上送的时候，估计服务员看到我们挂了请勿打扰灯，让前台打了电话来确认，刚好那个时间我们还在休息，电话来的时候会有一点感觉被吵醒到了。但总体来说这次入住非常不错的呢', '["https://dimg04.c-ctrip.com/images/0231v12000fhuiq43E951_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230b12000fhu3svwD0DE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h12000fhtpgqj4BDF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231212000fhufwt8C3A0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236p12000fhu9t8i841F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-11', '花园大床房', '大床房', '情侣出游', 466, 0, 4, 9, '["前台服务","客房服务","整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度'),
('68027c61e3c98b0941765a4b', '风景很好，酒店有文化历史风韵。下次还会入住这里，续住了一日，非常满意。酒店周边很多老酒家，适合美食爱好者。', '["https://dimg04.c-ctrip.com/images/0235k12000ds5ynjv34C1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230512000ds60lf740B3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232n12000ds5s3wh96AB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230712000ds5ni6j9D2F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-25', '花园双床房', '双床房', '家庭亲子', 53, 0, 4, 6, '["整体满意度","周边配套","景观/朝向"]'::jsonb, '整体满意度', '周边配套', '景观/朝向'),
('68027c61e3c98b0941765a4c', '设施：大堂非常的富丽堂皇，现在是圣诞节的布置了，好浪漫。?瀑布餐厅也不错，房间的层高略矮，?以如今已是38年了，设施有点老旧，但是还是蛮干净的，床上用品很舒服，如果放在38年前绝对是顶级奢华。??
过来过生日的，酒店帮忙升级的房间，还帮忙做了布置，前台还送的了鲜花，谢谢每一位热心且用心的工作人员。
酒店的花园也是精心设计过的，但是略小，现在只有异木棉在开放。
酒店博物馆还不错，听说有免费的讲解，但是没赶上。
上上下下里里外外的每一个工作人员态度都非常好，大堂里穿粉红色裙子的小姐姐会热心的帮忙拍，而且拍照技术很赞，感谢感谢！
早餐比较一般，种类比较，但是环境很好。
送的点心很好吃！谢谢！
因为胃不好，不然高低吃顿午饭再走。
整体感觉不错，都在五星的水准，里里外外逛了个遍，没事就在房间里面写写字，很安逸。

?', '["https://dimg04.c-ctrip.com/images/0235r12000cprsuos5E53_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231k12000cps3hjy3280_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231k12000cps169e203B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236z12000cprw22p8475_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235q12000cprvbztF677_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234412000cps3r2cB5F3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231812000cps3rgdF2C9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230912000cprxjenB7D7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233y12000cps2sb0D762_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-11', '红棉大床套房', '套房', '其他', 358, 1, 5, 9, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('68027c61e3c98b0941765a4d', '12555566666998888885555556666585555555555555555638885 九点不错！！', '["https://dimg04.c-ctrip.com/images/0235b12000eiqwg6m7688_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c12000eiqzilh8041_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000eiqt5zoE21E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-19', '花园大床房', '大床房', '情侣出游', 60, 0, 39, 0, '[]'::jsonb, NULL, NULL, NULL),
('68027c6ce3c98b0941765a4e', '作为全国3家白金五星级酒店，大堂富丽堂皇，后花园小桥流水，瀑布潺潺。4楼酒店博物馆不错，感受改革开放的岁月变迁，体会广州酒店业的发展历史和蓬勃生机。酒店门口地铁淘金站，去哪都很方便。稍显遗憾的是早餐种类不多，而且人多，排队时间长，体验不是很好。', '["https://dimg04.c-ctrip.com/images/0232d12000d6f3jvj4011_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230i12000d6f55izAE56_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235n12000d6eliyz4EBA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-11', '花园大床房', '大床房', '家庭亲子', 122, 0, 11, 9, '["交通便利性","餐饮设施","整体满意度"]'::jsonb, '交通便利性', '餐饮设施', '整体满意度'),
('68027c6ce3c98b0941765a4f', '本次购买的是套餐，包含自助晚餐和早餐，然后升级了一间房间为酒店景观房，十分美好，花园酒店虽然老牌但质量和服务依然上乘，房间设计精巧古典。食物也很好，很多人来吃自助，早餐最好也要早点去。附近可以去对面马路的友谊商店逛逛，是广州最早的进出口商店。也可以坐地铁或公交去天河体育西一带购物游玩，地点而言十分方便。', '["https://dimg04.c-ctrip.com/images/0230412000d9g31ae58CF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-21', '花园双床房', '双床房', '家庭亲子', 152, 0, 22, 8, '["餐饮设施","交通便利性","整体满意度"]'::jsonb, '餐饮设施', '交通便利性', '整体满意度'),
('68027c6ce3c98b0941765a50', '房间很奇葩，开放式卫生间，马桶间和淋浴室共用一扇非常难拉的拉门，可以想象*******便秘的场景，而且住到第三天被褥就会开始返潮……沟通了下前台，这种奇葩装修是老板喜欢，果然品味清奇。早餐八点左右必然排队，餐品挺难吃，我一便宜嘴巴说难吃就真真的千真万确了??，我觉得这种难吃是不以人的意志而转移的??。行政酒廊没烈酒和调酒，比较少见，全冷餐，在空调不行的情况下对老人和妇幼有点不和谐，基本上脱不了外套。酒店所有服务人员的素质很高，非常热情，仅次于海景花园了。行政酒廊的早餐点餐是冷的??', '["https://dimg04.c-ctrip.com/images/0234912000d2qxkre5497_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230z12000d2qvavt2D2A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233712000d2qo6602484_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000d2r6sw2D1E7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3, 3, '2024-01-29', '花园双床房', '双床房', '情侣出游', 243, 0, 12, 9, '["房间设施","餐饮设施","整体满意度"]'::jsonb, '房间设施', '餐饮设施', '整体满意度'),
('68027c6ce3c98b0941765a51', '花园酒店一直都是很稳定，先装修的房间很好，体现岭南设计风格。', '["https://dimg04.c-ctrip.com/images/02328224x8uwpfvld3CB7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-20', '花园大床房', '大床房', '商务出差', 30, 0, 11, 6, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('68027c6ce3c98b0941765a52', '老牌五星，广州人妇孺皆知的豪华酒店，硬件不会让人失望。服务在广州五星酒店里算比较好的，不过因为刚在上海和平饭店住过，感觉还有进一步提升空间，例如服务的主动，还有真诚。如果有机会，酒店的有关人不妨自己掏腰包，以普通客人的身份，去上海和平饭店住一晚，吃一次饭，参观一次酒店的博物馆，体验一下差距。作为一个老广州，真心希望花园酒店这个金子招牌擦得更亮。', '["https://dimg04.c-ctrip.com/images/0235t12000d2trhnt8953_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-30', '花园双床房', '双床房', '家庭亲子', 173, 0, 64, 8, '["整体满意度","前台服务","客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务'),
('68027c6ce3c98b0941765a53', '花园酒店的大堂很有特色，很多元素，中西合璧，金光闪闪，迎面的冲击感很强。
岭南花园是酒店的特色，有四层楼高的瀑布，南国绿植，小桥流水加悠游的锦鲤，是一派太平盛世的景象。
最喜欢的部份是四楼博物馆，小姐姐洪亮的嗓音，标准的普通话讲解，把酒店发展的历史，广州酒店的历史以及花园酒店的特色娓娓道来。', '["https://dimg04.c-ctrip.com/images/0230n12000d3cl8xeCEDF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232z12000d3cl57rF1C9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233v12000d3cl57t7958_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236g12000d3cl9p21263_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232u12000d3cl4ex2B90_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-31', '花园双床房', '双床房', '家庭亲子', 146, 0, 13, 9, '["公共设施","整体满意度"]'::jsonb, '公共设施', '整体满意度', NULL),
('68027c6ce3c98b0941765a54', '基本满意，但是2024/1/27日在瀑布餐厅早餐的时候被一名服务人员（餐厅做鸡蛋卷的那个厨师，具体名称不清楚，就是鸡蛋摊开放菜丁的那个蛋饼）搞的心情不好，他摊好一个之后放在了台子上，我没有意识到是别人预定的，我就打算拿，刚拿起来，他就大声说“Order，understand？” ，我就放了回去，我就不明白了，你面对国内的客人，有必要说英文吗？而且还是呵斥的口吻，我很震惊，五星级老牌酒店，这种服务态度，而且还带有崇洋的潜意识，什么年代了，无语，本想投诉给餐厅经理的，行程太紧，没时间，这里吐槽一下，酒店的服务，硬件和软服务缺一不可，而且温馨的软服务才是取胜之道，总之这个人的服务影响了我对花园酒店的印象！', '["https://dimg04.c-ctrip.com/images/0232k12000d2cu55f4519_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2024-01-28', '花园双床房', '双床房', '家庭亲子', 303, 2, 5, 8, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('68027c6ce3c98b0941765a55', '老牌白金五星底蕴还是非常深厚的 酒店本身就自带景点 餐饮配套等均在水准！
入住期间室外游泳池维修中没有体验 如有室内泳池更佳。
老酒店隔音是减分项，此次房间安排在布草间对面，保洁阿姨的开关门声聊天声都能听到，如对隔音有要求需慎选。', '["https://dimg04.c-ctrip.com/images/0232i12000d2loon5257A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232n12000d2lqkdx21B3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234u12000d2lretx6FA2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2024-01-29', '花园大床房', '大床房', '情侣出游', 115, 0, 4, 8, '["公共设施","安静程度","餐饮设施"]'::jsonb, '公共设施', '安静程度', '餐饮设施'),
('68027c6ce3c98b0941765a56', '一家有情怀有历史的老牌酒店是值得入住的，特别是四楼的博物馆绝对加分，让顾客了解酒店的昨天和今天；后花园的颜值也是值得欣赏的。但是由于房间安排在电梯旁晚上总有上上下下电梯的声音，体验度不是很好；加上晚上九点多楼上还在类似发出维修的电钻和敲打声，这个暴露了管理的不精细的有违酒店顾客的酒店文化。', '["https://dimg04.c-ctrip.com/images/0233112000d25pedm5F86_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233i12000d25pmxb0BED_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232h12000d25zenk5FE8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-01-27', '红棉大床套房', '套房', '家庭亲子', 145, 0, 4, 8, '["安静程度","整体满意度","公共设施"]'::jsonb, '安静程度', '整体满意度', '公共设施'),
('68027c6ce3c98b0941765a57', '酒店大堂富丽堂皇，第一眼看到有被震惊到，涨见识了！酒店处处是艺术风景，后花园也很美，值得来。这是一家有历史，文化底蕴的酒店，所以以前的房间设施相对旧点，但总体感受很好！', '["https://dimg04.c-ctrip.com/images/0232e12000d91lfstDB4C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233d12000d91ogui461E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000d91yjggFB1B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-02-20', '花园双床房', '双床房', '家庭亲子', 84, 0, 2, 7, '["整体满意度","公共设施","房间设施"]'::jsonb, '整体满意度', '公共设施', '房间设施'),
('68027c77e3c98b0941765a58', '??套餐里的行政早餐实在拉垮 自助部分屈指可数 点单部分第一天还行还有摆盘 第二天直接像换了厨师我的煎蛋们缩水了 吃了两天还是乖乖回一楼瀑布餐厅吃了 很热门 周末早餐到11点 11:30午市开始
??来之前得多刷刷评论啊 原来楼下在修地铁好像 避雷各楼层19-34号这一排房间（应该是）总之入住前一定要问清楚修路是哪一边的房间 第一晚凌晨两点还在开挖掘机真是服了 
??入住晚了 被告知楼层是吸烟楼层 会放一台空气净化器 
??后面的花园是真漂亮
??服务可以 礼宾部的几位不错
??出行方便 门口就是地铁', '["https://dimg04.c-ctrip.com/images/0234t12000d33hbc29989_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233v12000d33g5stCCD8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234112000d332dha3257_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236s12000d3383ng121B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234c12000d33gxp84AB7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000d3332tb57CA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-01-31', '粤韵双床套房', '套房', '家庭亲子', 253, 0, 15, 8, '["餐饮设施","安静程度","交通便利性"]'::jsonb, '餐饮设施', '安静程度', '交通便利性'),
('68027c77e3c98b0941765a59', '酒店紧邻地铁站，出行非常方便。酒店大堂非常壮观，一进去就忍不住要拍照，服务人员热情周到，但进入房间还是有点失望的，毕竟年头长了，设施老旧现状无法避免，洗浴池地漏堵水，洗个澡要洗洗停停，非常不便，期待改进！', '["https://dimg04.c-ctrip.com/images/0231y12000d24a48x782D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232f12000d24hlh4A9D9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000d24jqvfDFC0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-01-27', '花园双床房', '双床房', '家庭亲子', 102, 0, 22, 8, '["房间设施","交通便利性","前台服务"]'::jsonb, '房间设施', '交通便利性', '前台服务'),
('68027c77e3c98b0941765a5a', '酒店很大气，一入户，大厅里金碧辉煌，那面超大的金色背景墙给人一种震撼的感觉。服务人员很热情，主动提行李，主动递水，主动发小礼物，电梯口的小姐姐每次一见面都要给小朋友一大把小点心，客服部也是有求必应。后面还有瀑布大花园，很漂亮。外面一出门就是地铁5号线，非常方便，离小蛮腰也很近。整体超赞。', '["https://dimg04.c-ctrip.com/images/0231712000d7kkvnnBA2F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230l12000d7k88qq274D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-15', '花园大床房', '大床房', '家庭亲子', 144, 0, 3, 9, '["整体满意度","前台服务","交通便利性"]'::jsonb, '整体满意度', '前台服务', '交通便利性'),
('68027c77e3c98b0941765a5b', '挺不错的，交通挺方便的', '["https://dimg04.c-ctrip.com/images/0230512000exzm2r16556_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000exzhytq0DB2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-30', '花园双床房', '双床房', '家庭亲子', 11, 0, 10, 4, '["交通便利性","整体满意度"]'::jsonb, '交通便利性', '整体满意度', NULL)
 ON CONFLICT (_id) DO NOTHING;
